                "content": "key is [REDACTED_AWS_KEY_ID] here"}}
        out = c.slim_line(line)
        self.assertNotIn("[REDACTED_AWS_KEY_ID]", json.dumps(out))
        self.assertIn("[REDACTED_AWS_KEY_ID]", json.dumps(out))

    def test_password_backtick_redacted(self):
        line = {"type": "user", "message": {"role": "user",
                "content": "set the password `[REDACTED]` now"}}
        out = c.slim_line(line)
        self.assertNotIn("`kalhar`", json.dumps(out))
        self.assertIn("[REDACTED]", json.dumps(out))

