                "content": "ghp_" + "a" * 36 + " and sk-" + "b" * 32}}
        s = json.dumps(c.slim_line(line))
        self.assertIn("[REDACTED_GITHUB_TOKEN]", s)
        self.assertIn("[REDACTED_API_KEY]", s)

    def test_image_data_never_redacted(self):
        # craft base64 data that contains an AKIA-looking run; must stay intact
        payload = "AKIA" + "A" * 16 + IMG_DATA
        line = {"type": "assistant", "message": {"role": "assistant", "content": [
            {"type": "image", "source": {"type": "base64",
             "media_type": "image/png", "data": payload}}]}}
        out = c.slim_line(line)
        self.assertEqual(out["message"]["content"][0]["source"]["data"], payload)

